# cursor_pagination.py -- minimal cursor-paginated list endpoint
# Requires: pip install flask

import base64
import json
import sqlite3
from flask import Flask, request, jsonify, g

app = Flask(__name__)
DB = "items.db"

def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DB)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_db(exc):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def init_db():
    with app.app_context():
        db = get_db()
        db.execute("""
            CREATE TABLE IF NOT EXISTS items (
                id         INTEGER PRIMARY KEY AUTOINCREMENT,
                name       TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT (datetime('now'))
            )
        """)
        db.execute("""
            CREATE INDEX IF NOT EXISTS idx_items_keyset
            ON items (created_at, id)
        """)
        if db.execute("SELECT COUNT(*) FROM items").fetchone()[0] == 0:
            for i in range(1, 201):
                db.execute(
                    "INSERT INTO items (name) VALUES (?)",
                    (f"item-{i:03d}",)
                )
        db.commit()

def encode_cursor(created_at: str, item_id: int) -> str:
    payload = json.dumps({"created_at": created_at, "id": item_id})
    return base64.urlsafe_b64encode(payload.encode()).decode()

def decode_cursor(cursor: str):
    try:
        payload = base64.urlsafe_b64decode(cursor.encode()).decode()
        data = json.loads(payload)
        return data["created_at"], data["id"]
    except Exception:
        return None, None

@app.get("/items")
def list_items():
    try:
        limit = min(int(request.args.get("limit", 20)), 100)
    except ValueError:
        return jsonify(error="limit must be an integer"), 400

    cursor_str = request.args.get("cursor")
    db = get_db()

    if cursor_str:
        ts, last_id = decode_cursor(cursor_str)
        if ts is None:
            return jsonify(error="invalid cursor"), 400
        rows = db.execute(
            """
            SELECT id, name, created_at FROM items
            WHERE (created_at > ? OR (created_at = ? AND id > ?))
            ORDER BY created_at, id LIMIT ?
            """,
            (ts, ts, last_id, limit + 1)
        ).fetchall()
    else:
        rows = db.execute(
            "SELECT id, name, created_at FROM items ORDER BY created_at, id LIMIT ?",
            (limit + 1,)
        ).fetchall()

    has_more = len(rows) > limit
    page = rows[:limit]
    next_cursor = None
    if has_more and page:
        last = page[-1]
        next_cursor = encode_cursor(last["created_at"], last["id"])

    return jsonify(
        data=[dict(r) for r in page],
        next_cursor=next_cursor,
        has_more=has_more
    )

if __name__ == "__main__":
    init_db()
    app.run(debug=True, port=5001)

# paginated_client.py -- traverse all pages, respect 429 with backoff
# Requires: pip install httpx

import time
import httpx
from typing import Iterator, Any

def iter_all_items(
    base_url: str,
    api_key: str,
    page_size: int = 50,
    max_retries: int = 4,
) -> Iterator[Any]:
    """
    Generator: yields every item across all pages.
    Respects X-RateLimit-Remaining to self-throttle proactively.
    Handles 429 with Retry-After backoff.
    """
    cursor = None
    headers = {"Authorization": f"Bearer {api_key}"}

    while True:
        params = {"limit": page_size}
        if cursor:
            params["cursor"] = cursor

        response = None
        for attempt in range(max_retries):
            r = httpx.get(
                f"{base_url}/items",
                params=params,
                headers=headers,
                timeout=10,
            )
            if r.status_code == 200:
                response = r
                break
            elif r.status_code == 429:
                wait = float(r.headers.get("Retry-After", 2 ** attempt))
                print(f"  Rate limited. Waiting {wait:.1f}s (attempt {attempt+1})")
                time.sleep(wait)
            else:
                r.raise_for_status()

        if response is None:
            raise RuntimeError(f"Rate-limit retries exhausted after {max_retries} attempts")

        remaining = response.headers.get("X-RateLimit-Remaining", "?")
        limit = response.headers.get("X-RateLimit-Limit", "?")
        print(f"  Page fetched | remaining={remaining}/{limit}")

        # Proactive self-throttle: if headroom is low, slow down
        try:
            if int(remaining) < 5:
                reset_ts = int(response.headers.get("X-RateLimit-Reset", 0))
                wait = max(0, reset_ts - int(time.time()))
                if wait > 0:
                    print(f"  Headroom low, waiting {wait}s for reset")
                    time.sleep(wait)
        except (ValueError, TypeError):
            pass

        body = response.json()
        for item in body["data"]:
            yield item

        if not body.get("has_more"):
            break
        cursor = body["next_cursor"]


if __name__ == "__main__":
    all_items = list(iter_all_items("http://localhost:5001", api_key="demo-key"))
    print(f"Total items: {len(all_items)}")
